// Build the LLM system + user prompt from the transcript service response.
// Mirrors the AgeniusDesk youtube-research SINGLE_PASS breakdown.
const d = $input.first().json;
const title = d.title || '';
const channel = d.channel || '';
const url = d.url || '';
const transcript = d.text || '';

const system = 'You are a senior engineer and technical analyst. You turn a raw video ' +
  'transcript into a dense, accurate research breakdown that a builder can learn from and ' +
  'put into practice. You write plainly, no corporate filler, no em-dashes. You never invent ' +
  'claims the transcript does not support. When the transcript has artifacts (repeated lines ' +
  'from caption VAD), you silently de-duplicate them.';

const userPrompt =
  'Produce a research breakdown of this video as GitHub-flavored markdown.\n\n' +
  'Video: ' + (title || '(unknown title)') + '\n' +
  'Channel: ' + (channel || '(unknown)') + '\n' +
  'URL: ' + url + '\n\n' +
  'Structure the breakdown with these sections (use ## headers):\n\n' +
  '1. **One-line thesis** - the single core argument.\n' +
  '2. **Key concepts** - each major idea, defined clearly. Use subsections.\n' +
  '3. **Architectures / systems / workflows** - any concrete technical structure described ' +
  '(pipelines, loops, components). Be precise.\n' +
  '4. **Notable techniques and golden nuggets** - the practical, actionable bits.\n' +
  '5. **Tools, people, and resources named** - with a one-line note on each.\n' +
  '6. **How to apply this** - map the ideas onto the reader\'s own stack: what is worth ' +
  'adopting and the concrete next step. Be specific and opinionated.\n\n' +
  'Rules:\n' +
  '- Faithful to the transcript. Do not fabricate.\n' +
  '- Dense and skimmable. Tables and bullets over paragraphs where it helps.\n' +
  '- No em-dashes. No hype words (groundbreaking, revolutionary, game-changing).\n\n' +
  'Transcript:\n---\n' + transcript + '\n---\n';

return [{ json: Object.assign({}, d, { system: system, userPrompt: userPrompt }) }];

// Assemble the final markdown note (frontmatter + LLM breakdown) and a filename.
const meta = $('Fetch Transcript').first().json;
const body = $input.first().json; // Anthropic response

let text = '';
try {
  text = (body.content || [])
    .filter(function (b) { return b.type === 'text'; })
    .map(function (b) { return b.text; })
    .join('\n')
    .trim();
} catch (e) { text = ''; }
if (!text) { throw new Error('LLM returned no text'); }

const title = meta.title || 'Untitled';
const channel = meta.channel || '';
const url = meta.url || '';
const videoId = meta.video_id || '';

function slugify(s) {
  return (s || 'note').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').substring(0, 80) || 'note';
}
const q = function (s) { return String(s || '').replace(/"/g, '\\"'); };
const date = new Date().toISOString().split('T')[0];
const filename = slugify(title) + '-' + videoId + '.md';

const frontmatter =
  '---\n' +
  'title: "' + q(title) + '"\n' +
  'source: ' + url + '\n' +
  'channel: "' + q(channel) + '"\n' +
  'video_id: ' + videoId + '\n' +
  'captured: ' + date + '\n' +
  'type: youtube-research\n' +
  '---\n\n';

const markdown = frontmatter + '# ' + title + '\n\n' + text + '\n';

return [{ json: { filename: filename, markdown: markdown, title: title, video_id: videoId, source: url } }];
